// AsBytes get the raw file content as bytes.
//
// This provides zero-copy access to the underlying buffer.
func (r *UploadFile) AsBytes() (*[]byte, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.spikard_upload_file_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	defer C.spikard_upload_file_free(cRecv)
	ptr := C.spikard_upload_file_as_bytes(cRecv)
	defer C.spikard_free_string(ptr)
	return unmarshalBytes(ptr), nil
}

// ReadToString read the file content as a UTF-8 string.
//
// # Errors
//
// Returns an error if the content is not valid UTF-8.
func (r *UploadFile) ReadToString() (*string, error) {
	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return nil, fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.spikard_upload_file_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	defer C.spikard_upload_file_free(cRecv)
	ptr := C.spikard_upload_file_read_to_string(cRecv)
	if err := lastError(); err != nil {
		if ptr != nil {
			C.spikard_free_string(ptr)
		}
		return nil, err
	}
	defer C.spikard_free_string(ptr)
	return func() *string { v := C.GoString(ptr); return &v }(), nil
}

