// SetCookie set a cookie in the response
func (r *Response) SetCookie(key string, value string, secure bool, httpOnly bool, maxAge *int64, domain *string, path *string, sameSite *string) error {
	cKey := C.CString(key)
	defer C.free(unsafe.Pointer(cKey))

	cValue := C.CString(value)
	defer C.free(unsafe.Pointer(cValue))

	var cSecure C.int32_t
	if secure {
		cSecure = 1
	} else {
		cSecure = 0
	}

	var chttpOnly C.int32_t
	if httpOnly {
		chttpOnly = 1
	} else {
		chttpOnly = 0
	}

	var cMaxAge C.int64_t = C.int64_t(int64(9223372036854775807))
	if maxAge != nil {
		cMaxAge = C.int64_t(int64(*maxAge))
	}

	var cDomain *C.char
	if domain != nil {
		cDomain = C.CString(*domain)
		defer C.free(unsafe.Pointer(cDomain))
	}

	var cPath *C.char
	if path != nil {
		cPath = C.CString(*path)
		defer C.free(unsafe.Pointer(cPath))
	}

	var cSameSite *C.char
	if sameSite != nil {
		cSameSite = C.CString(*sameSite)
		defer C.free(unsafe.Pointer(cSameSite))
	}

	jsonBytesRecv, err := json.Marshal(r)
	if err != nil {
		return fmt.Errorf("failed to marshal receiver: %w", err)
	}
	tmpStrRecv := C.CString(string(jsonBytesRecv))
	cRecv := C.spikard_response_from_json(tmpStrRecv)
	C.free(unsafe.Pointer(tmpStrRecv))
	defer C.spikard_response_free(cRecv)
	C.spikard_response_set_cookie(cRecv, cKey, cValue, cSecure, chttpOnly, cMaxAge, cDomain, cPath, cSameSite)
	jsonPtrUpdated := C.spikard_response_to_json(cRecv)
	if jsonPtrUpdated != nil {
		_ = json.Unmarshal([]byte(C.GoString(jsonPtrUpdated)), r)
		C.spikard_free_string(jsonPtrUpdated)
	}
	return nil
}

